  ]
}

Here are the public test cases for feature11_3_remote_uri:
{
  "description": "Reconstruct the remote repository URL from credential-query arguments. The URL requires both protocol and host; if either is missing no URL is produced. The host may carry a port as 'host:port'. The path, when present, is appended. By default the username is omitted; when user inclusion is requested the username is URL-encoded and embedded in the authority, but the password is never included.",
  "cases": [
    {
      "input": {
        "op": "remote_uri",
        "arguments": {}
      },
      "expected_output": "uri=<none>\n"
    },
    {
      "input": {
        "op": "remote_uri",
        "arguments": {
          "protocol": "https",
          "host": "example.com"
        }
      },
      "expected_output": "uri=https://example.com/\n"
    },
    {
      "input": {
        "op": "remote_uri",
        "arguments": {
          "protocol": "https",
          "host": "example.com:456"
        }
      },
      "expected_output": "uri=https://example.com:456/\n"
    },
    {
      "input": {
        "op": "remote_uri",
        "arguments": {
          "protocol": "https",
          "host": "example.com",
          "path": "an/example/path"
        }
      },
      "expected_output": "uri=https://example.com/an/example/path\n"
    },
    {
      "input": {
        "op": "remote_uri",
        "arguments": {
          "protocol": "https",
          "host": "example.com",
          "path": "an/example/path",
          "username": "john.doe",
          "password": "password123"
        }
      },
      "expected_output": "uri=https://example.com/an/example/path\n"
    },
    {
      "input": {
        "op": "remote_uri",
        "include_user": true,
        "arguments": {
          "protocol": "https",
          "host": "example.com",
          "username": "john.doe",
          "password": "password123"
        }
      },
      "expected_output": "uri=https://john.doe@example.com/\n"
    },
    {
      "input": {
        "op": "remote_uri",
        "include_user": true,
        "arguments": {
          "protocol": "https",
          "host": "example.com",
          "username": "john.doe@domain.com",
          "password": "password123"
        }
      },
      "expected_output": "uri=https://john.doe%40domain.com@example.com/\n"
    },
    {
      "input": {
        "op": "remote_uri",
        "include_user": true,
        "arguments": {
          "protocol": "https",
          "host": "example.com",
          "path": "an/example/path",
          "username": "john.doe",
          "password": "password123"
        }
      },
      "expected_output": "uri=https://john.doe@example.com/an/example/path\n"
    }
  ]
}

Here are the public test cases for feature11_4_host_port:
{
  "description": "Split the host field of a credential query into a hostname and optional numeric port. A host with no colon yields the hostname and no port. A host of the form 'name:number' yields the hostname and the parsed port. A host whose port portion is non-numeric is rejected as invalid. A missing host is also rejected as invalid.",
  "cases": [
    {
      "input": {
        "op": "host_port",
        "arguments": {
          "protocol": "https",
          "host": "example.com"
        }
      },
      "expected_output": "valid=true\nhost=example.com\nport=<none>\n"
    },
    {
      "input": {
        "op": "host_port",
        "arguments": {
          "protocol": "https",
          "host": "example.com:456"
        }
      },
      "expected_output": "valid=true\nhost=example.com\nport=456\n"
    },
    {
      "input": {
        "op": "host_port",
        "arguments": {
          "protocol": "https",
          "host": "example.com:not-a-port"
        }
      },
      "expected_output": "valid=false\n"
    },
    {
      "input": {
        "op": "host_port",
        "arguments": {
          "protocol": "https"
        }
      },
      "expected_output": "valid=false\n"
    }
  ]
}

Here are the public test cases for feature12_range_check:
{
  "description": "Validate that an integer falls within a range defined by a lower and upper bound, where each bound can independently be inclusive or exclusive. A value satisfying the bounds is in range; a value violating either bound is reported as an out-of-range error. With both bounds inclusive, the endpoints themselves are accepted; making a bound exclusive rejects that endpoint.",
  "cases": [
    {
      "input": {
        "op": "range_check",
        "value": 5,
        "lower": 0,
        "upper": 10,
        "lower_inclusive": true,
        "upper_inclusive": true
      },
      "expected_output": "in_range=true\n"
    },
    {
      "input": {
        "op": "range_check",
        "value": 0,
        "lower": 0,
        "upper": 10,
        "lower_inclusive": true,
        "upper_inclusive": true
      },
      "expected_output": "in_range=true\n"
    },
    {
      "input": {
        "op": "range_check",
        "value": 10,
        "lower": 0,
        "upper": 10,
        "lower_inclusive": true,
        "upper_inclusive": true
      },
      "expected_output": "in_range=true\n"
    },
    {
      "input": {
        "op": "range_check",
        "value": -10,
        "lower": -10,
        "upper": 0,
        "lower_inclusive": true,
        "upper_inclusive": true
      },
      "expected_output": "in_range=true\n"
    },
    {
      "input": {
        "op": "range_check",
        "value": 13,
        "lower": 0,
        "upper": 10,
        "lower_inclusive": true,
        "upper_inclusive": true
      },
      "expected_output": "error=out_of_range\n"
    },
    {
      "input": {
        "op": "range_check",
        "value": -3,
        "lower": 0,
        "upper": 10,
        "lower_inclusive": true,
        "upper_inclusive": true
      },
      "expected_output": "error=out_of_range\n"
    },
    {
      "input": {
        "op": "range_check",
        "value": 10,
        "lower": 0,
        "upper": 10,
        "lower_inclusive": true,
        "upper_inclusive": false
      },
      "expected_output": "error=out_of_range\n"
    },
    {
      "input": {
        "op": "range_check",
        "value": 0,
        "lower": 0,
        "upper": 10,
        "lower_inclusive": false,
        "upper_inclusive": true
      },
      "expected_output": "error=out_of_range\n"
    }
  ]
}

Here are the public test cases for feature1_1_boolean_classify:
{
  "description": "Classify a configuration string against Git's boolean conventions. Several spellings are equivalent to true (true/yes/on/1) and several to false (false/no/off/0), all case-insensitive; any other text (including empty, whitespace, or unset) is neither. Output reports whether the value is truthy, whether it is falsey, and the combined three-state interpretation (true, false, or none).",
  "cases": [
    {
      "input": {
        "op": "git_boolean",
        "value": "true"
      },
      "expected_output": "truthy=true\nfalsey=false\nbooleany=true\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "YES"
      },
      "expected_output": "truthy=true\nfalsey=false\nbooleany=true\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "oN"
      },
      "expected_output": "truthy=true\nfalsey=false\nbooleany=true\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "1"
      },
      "expected_output": "truthy=true\nfalsey=false\nbooleany=true\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "OFF"
      },
      "expected_output": "truthy=false\nfalsey=true\nbooleany=false\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "no"
      },
      "expected_output": "truthy=false\nfalsey=true\nbooleany=false\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "0"
      },
      "expected_output": "truthy=false\nfalsey=true\nbooleany=false\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "i am a random string"
      },
      "expected_output": "truthy=false\nfalsey=false\nbooleany=none\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": ""
      },
      "expected_output": "truthy=false\nfalsey=false\nbooleany=none\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": "     "
      },
      "expected_output": "truthy=false\nfalsey=false\nbooleany=none\n"
    },
    {
      "input": {
        "op": "git_boolean",
        "value": null
      },
      "expected_output": "truthy=false\nfalsey=false\nbooleany=none\n"
    }
  ]
}

Here are the public test cases for feature1_2_boolean_or_default:
{
  "description": "Interpret a configuration string as a boolean, but fall back to a caller-supplied default when the value is not a recognized boolean spelling. Recognized truthy spellings return true and recognized falsey spellings return false regardless of the default; any unrecognized value (including empty, whitespace, or unset) returns the provided default.",
  "cases": [
    {
      "input": {
        "op": "booleany_or_default",
        "value": "yes",
        "default": false
      },
      "expected_output": "result=true\n"
    },
    {
      "input": {
        "op": "booleany_or_default",
        "value": "OFF",
        "default": true
      },
      "expected_output": "result=false\n"
    },
    {
      "input": {
        "op": "booleany_or_default",
        "value": "i am a random string",
        "default": true
      },
      "expected_output": "result=true\n"
    },
    {
      "input": {
        "op": "booleany_or_default",
        "value": "i am a random string",
        "default": false
      },
      "expected_output": "result=false\n"
    },
    {
      "input": {
        "op": "booleany_or_default",
        "value": null,
        "default": true
      },
      "expected_output": "result=true\n"
    },
    {
      "input": {
        "op": "booleany_or_default",
        "value": "",
        "default": false
      },
      "expected_output": "result=false\n"
    }
  ]
}

Here are the public test cases for feature2_1_keep_prefix:
{
  "description": "Keep the portion of a string before a delimiter character, discarding the delimiter and everything after it. With anchor 'first', the cut is made at the first occurrence of the delimiter; with anchor 'last', the cut is made at the last occurrence. A string with no delimiter is returned unchanged. Passing an absent (null) string is an error reported as a null-argument condition.",
  "cases": [
    {
      "input": {
        "op": "keep_prefix",
        "text": "",
        "delimiter": "/",
        "anchor": "first"
      },
      "expected_output": "result=\n"
    },
    {
      "input": {
        "op": "keep_prefix",
        "text": "/",
        "delimiter": "/",
        "anchor": "first"
      },
      "expected_output": "result=\n"
    },
    {
      "input": {
        "op": "keep_prefix",
        "text": "foo",
        "delimiter": "/",
        "anchor": "first"
      },
      "expected_output": "result=foo\n"
    },
    {
      "input": {
        "op": "keep_prefix",
        "text": "foo/bar",
        "delimiter": "/",
        "anchor": "first"
      },
      "expected_output": "result=foo\n"
    },
    {
      "input": {
        "op": "keep_prefix",
        "text": "foo/bar/",
        "delimiter": "/",
        "anchor": "first"
      },
      "expected_output": "result=foo\n"
    },
    {
      "input": {
        "op": "keep_prefix",
        "text": "foo/bar",
        "delimiter": "/",
        "anchor": "last"
      },
      "expected_output": "result=foo\n"
    },
    {
      "input": {
        "op": "keep_prefix",
        "text": "foo/bar/",
        "delimiter": "/",
        "anchor": "last"
      },
      "expected_output": "result=foo/bar\n"
    },
    {
      "input": {
        "op": "keep_prefix",
        "text": null,
        "delimiter": "/",
        "anchor": "first"
      },
      "expected_output": "error=argument_null\n"
    }
  ]
}

Here are the public test cases for feature2_2_keep_suffix:
