Here are the public test cases for feature3_base64url:
{
  "description": "Encode a byte array into the URL-safe base64 alphabet, where byte 62 is '-' and byte 63 is '_' instead of '+' and '/'. With padding enabled the output keeps trailing '=' padding to a multiple of four characters; with padding disabled the trailing '=' characters are removed. An empty input produces an empty string.",
  "cases": [
    {
      "input": {
        "op": "base64url",
        "bytes": [],
        "padding": true
      },
      "expected_output": "base64url=\n"
    },
    {
      "input": {
        "op": "base64url",
        "bytes": [
          4
        ],
        "padding": true
      },
      "expected_output": "base64url=BA==\n"
    },
    {
      "input": {
        "op": "base64url",
        "bytes": [
          4,
          5
        ],
        "padding": true
      },
      "expected_output": "base64url=BAU=\n"
    },
    {
      "input": {
        "op": "base64url",
        "bytes": [
          4,
          5,
          6
        ],
        "padding": true
      },
      "expected_output": "base64url=BAUG\n"
    },
    {
      "input": {
        "op": "base64url",
        "bytes": [
          4,
          5,
          6,
          7
        ],
        "padding": true
      },
      "expected_output": "base64url=BAUGBw==\n"
    },
    {
      "input": {
        "op": "base64url",
