      },
      "expected_output": "present=true\nusername=john.doe\npassword=password123\n"
    },
    {
      "input": {
        "op": "user_info",
        "uri": "http://john.doe@example.com"
      },
      "expected_output": "present=true\nusername=john.doe\npassword=<unset>\n"
    },
    {
      "input": {
        "op": "user_info",
        "uri": "http://john.doe:@example.com"
      },
